import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';

const AdminPage = () => {
  const navigate = useNavigate();

  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [comments, setComments] = useState([]);

  const [tab, setTab] = useState('users');
  const [themeTrigger, setThemeTrigger] = useState(false);

  useEffect(() => {
    API.get('/admin/users').then(res => setUsers(res.data));
    API.get('/admin/posts').then(res => setPosts(res.data));
    API.get('/admin/comments').then(res => setComments(res.data));
  }, []);

  useEffect(() => {
    const handleThemeChange = () => {
      setThemeTrigger(prev => !prev);
    };

    window.addEventListener("storage", handleThemeChange);
    return () => window.removeEventListener("storage", handleThemeChange);
  }, []);

  const toggleStatus = async (id) => {
    const { data } = await API.put(`/admin/users/${id}/status`);
    setUsers(users.map(u => (u._id === id ? data.user : u)));
  };

  /* ================= PERMANENT DELETE POST ================= */
  const removePost = async (id) => {
    if (!window.confirm("Are you sure you want to permanently delete this post?")) return;

    try {
      // Use DELETE for permanent removal. 
      // Note: Ensure your backend has a DELETE route for this or handles the PUT as a hard delete.
      await API.delete(`/posts/${id}`); 
      
      // Completely remove from local state
      setPosts(posts.filter(p => p._id !== id));
    } catch (err) {
      console.error("Failed to delete post:", err);
      alert("Error deleting post.");
    }
  };

  const deleteComment = async (id) => {
    await API.delete(`/comments/${id}`);
    setComments(comments.filter(c => c._id !== id));
  };

  const viewPost = (postId) => {
    navigate(`/post/${postId}`);
  };

  const isDark = document.body.classList.contains('dark-mode');

  const styles = {
    page: {
      backgroundColor: isDark ? '#560032' : '#FAE8ED',
      minHeight: '100vh',
      padding: '30px',
      fontFamily: 'Georgia, serif',
      color: isDark ? '#f5d6e6' : 'rgb(12, 75, 52)',
    },
    container: {
      maxWidth: '1100px',
      margin: '0 auto',
      backgroundColor: isDark ? '#2e091e' : '#f7c6d9',
      padding: '30px',
      borderRadius: '20px',
      boxShadow: '0 10px 30px rgba(0,0,0,0.1)',
    },
    heading: {
      fontSize: '36px',
      textAlign: 'center',
      marginBottom: '20px',
      fontWeight: 'bold',
    },
    tabs: {
      display: 'flex',
      justifyContent: 'center',
      gap: '10px',
      marginBottom: '20px',
    },
    tabButton: {
      padding: '10px 25px',
      borderRadius: '50px',
      border: 'none',
      cursor: 'pointer',
      fontWeight: 'bold',
      backgroundColor: isDark ? '#3a253a' : '#ffffff',
      color: isDark ? '#f5d6e6' : '#555',
      transition: '0.3s',
    },
    activeTab: {
      backgroundColor: isDark ? '#eda0ae' : 'rgb(12, 75, 52)',
      color: '#fff',
    },
    table: {
      width: '100%',
      borderCollapse: 'collapse',
      backgroundColor: isDark ? '#3a253a' : '#fff',
      borderRadius: '12px',
      overflow: 'hidden',
    },
    th: {
      padding: '12px',
      backgroundColor: isDark ? '#4a2e4a' : 'rgb(12, 75, 52)',
      color: '#fff',
      textAlign: 'left',
    },
    td: {
      padding: '10px',
      borderBottom: '1px solid #ccc',
      color: isDark ? '#f5d6e6' : 'inherit',
    },
    button: {
      padding: '6px 14px',
      borderRadius: '10px',
      border: 'none',
      cursor: 'pointer',
      marginRight: '5px',
      fontWeight: 'bold',
    },
    dangerBtn: {
      backgroundColor: '#ff4d6d',
      color: '#fff',
    },
    viewBtn: {
      backgroundColor: '#6c63ff',
      color: '#fff',
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h2 style={styles.heading}>Admin Dashboard</h2>

        <div style={styles.tabs}>
          <button
            onClick={() => setTab('users')}
            style={{ ...styles.tabButton, ...(tab === 'users' ? styles.activeTab : {}) }}
          >
            Users ({users.length})
          </button>

          <button
            onClick={() => setTab('posts')}
            style={{ ...styles.tabButton, ...(tab === 'posts' ? styles.activeTab : {}) }}
          >
            Posts ({posts.length})
          </button>

          <button
            onClick={() => setTab('comments')}
            style={{ ...styles.tabButton, ...(tab === 'comments' ? styles.activeTab : {}) }}
          >
            Comments ({comments.length})
          </button>
        </div>

        {/* USERS TAB */}
        {tab === 'users' && (
          <table style={styles.table}>
            <thead>
              <tr>
                <th style={styles.th}>Name</th>
                <th style={styles.th}>Email</th>
                <th style={styles.th}>Status</th>
                <th style={styles.th}>Action</th>
              </tr>
            </thead>
            <tbody>
              {users.map(u => (
                <tr key={u._id}>
                  <td style={styles.td}>{u.name}</td>
                  <td style={styles.td}>{u.email}</td>
                  <td style={styles.td}>{u.status}</td>
                  <td style={styles.td}>
                    <button
                      style={{ ...styles.button, ...styles.dangerBtn }}
                      onClick={() => toggleStatus(u._id)}
                    >
                      {u.status === 'active' ? 'Deactivate' : 'Activate'}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}

        {/* POSTS TAB - UPDATED */}
        {tab === 'posts' && (
          <table style={styles.table}>
            <thead>
              <tr>
                <th style={styles.th}>Title</th>
                <th style={styles.th}>Author</th>
                <th style={styles.th}>Action</th>
              </tr>
            </thead>
            <tbody>
              {posts.map(p => (
                <tr key={p._id}>
                  <td style={styles.td}>{p.title}</td>
                  <td style={styles.td}>{p.author?.name || 'Unknown'}</td>
                  <td style={styles.td}>
                    <button
                      style={{ ...styles.button, ...styles.viewBtn }}
                      onClick={() => viewPost(p._id)}
                    >
                      View
                    </button>
                    <button
                      style={{ ...styles.button, ...styles.dangerBtn }}
                      onClick={() => removePost(p._id)}
                    >
                      Delete Forever
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}

        {/* COMMENTS TAB */}
        {tab === 'comments' && (
          <table style={styles.table}>
            <thead>
              <tr>
                <th style={styles.th}>Author</th>
                <th style={styles.th}>Comment</th>
                <th style={styles.th}>Action</th>
              </tr>
            </thead>
            <tbody>
              {comments.map(c => (
                <tr key={c._id}>
                  <td style={styles.td}>{c.author?.name}</td>
                  <td style={styles.td}>{c.body}</td>
                  <td style={styles.td}>
                    <button
                      style={{ ...styles.button, ...styles.dangerBtn }}
                      onClick={() => deleteComment(c._id)}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default AdminPage;
